import { By } from "selenium-webdriver";
import ojwd, { DriverLike, register } from "../../";
import { OjSlider } from "./OjSlider";
export { OjSlider };

/**
 * Create an instance of [[OjSlider]].  This function will first wait for
 * the element to appear in the DOM before trying to locate it.
 * @example
 * <code>
 * const el = await ojSlider(driver, By.id('my-oj-slider'))
 * </code>
 * @param driver A WebDriver/WebElement instance used to locate the component
 * element.
 * @param by The By locator with which to find the element
 */
export async function ojSlider(driver: DriverLike, by: By): Promise<OjSlider> {
  const webEl = await driver.findElement(by);
  // Check that the element is of type OjSlider
  if (!(webEl instanceof OjSlider)) {
    const tagName = await webEl.getTagName();
    throw Error(`Locator '${by}' located a <${tagName}>, but expected <oj-slider>`);
  }
  return webEl;
}

register("oj-slider", OjSlider);
